  val n = s.length
  val dp = Array.ofDim[Int](n, n)

  for (length <- 2 to n) {
    for (i <- 0 to n - length) {
      val j = i + length - 1
      if (s(i) == s(j)) {
        dp(i)(j) = dp(i + 1)(j - 1)
      } else {
        dp(i)(j) = math.min(dp(i + 1)(j), dp(i)(j - 1)) + 1
      }
    }
