def reverseString(s: String, k: Int): String = {
  val sb = new StringBuilder
  val n = s.length

  for (i <- 0 until n by 2 * k) {
    // Reverse the first k characters of the current chunk
    val firstK = s.slice(i, i + k).reverse
    // Append the first k reversed characters and the remaining part of the chunk
    sb.append(firstK).append(s.slice(i + k, i + 2 * k))
  }

  sb.toString()
}

// Test cases
